import { data, takaro } from '@takaro/helpers';

async function main() {
    const { gameServerId, player, pog, arguments: args, module } = data;
    const amount = parseInt(args.amount);

    if (isNaN(amount) || amount <= 0) {
        throw new TakaroUserError('Amount must be a positive number.');
    }

    const playerId = `EOS_${pog.gameId}`;

    // Check player inventory first
    const inventoryResult = await takaro.gameserver.gameServerControllerExecuteCommand(gameServerId, {
        command: `si ${playerId}`
    });

    const rawResult = inventoryResult.data.data.rawResult;
    const lines = rawResult.split('\n');
    let availableCoins = 0;
    for (const line of lines) {
        const match = line.match(/Slot \d+: (\d+) \* casinoCoin/);
        if (match) {
            availableCoins += parseInt(match[1]);
        }
    }

    if (availableCoins < amount) {
        throw new TakaroUserError(`You only have ${availableCoins} coins on you. Cannot deposit ${amount}.`);
    }

    // Remove coins from inventory FIRST
    await takaro.gameserver.gameServerControllerExecuteCommand(gameServerId, {
        command: `rii "${player.name}" casinoCoin ${amount}`
    });

    // THEN update bank balance
    const moduleId = module.moduleId;
    const variables = await takaro.variable.variableControllerSearch({
        filters: {
            key: ['bankBalance'],
            gameServerId: [gameServerId],
            playerId: [pog.playerId],
            moduleId: [moduleId]
        }
    });

    const currentBalance = variables.data.data.length > 0 ? parseInt(variables.data.data[0].value) : 0;
    const newBalance = currentBalance + amount;

    if (variables.data.data.length > 0) {
        await takaro.variable.variableControllerUpdate(variables.data.data[0].id, {
            value: newBalance.toString()
        });
    } else {
        await takaro.variable.variableControllerCreate({
            key: 'bankBalance',
            value: newBalance.toString(),
            gameServerId,
            playerId: pog.playerId,
            moduleId
        });
    }

    await takaro.gameserver.gameServerControllerSendMessage(gameServerId, {
        message: `[Bank] Deposited ${amount} coins. New balance: ${newBalance} coins.`,
        opts: { recipient: { gameId: pog.gameId } }
    });
}

await main();

import { data, takaro } from '@takaro/helpers';

async function main() {
    const { gameServerId, player, pog, arguments: args, module } = data;
    const amount = parseInt(args.amount);

    if (isNaN(amount) || amount <= 0) {
        throw new TakaroUserError('Amount must be a positive number.');
    }

    const moduleId = module.moduleId;

    // Check balance first
    const variables = await takaro.variable.variableControllerSearch({
        filters: {
            key: ['bankBalance'],
            gameServerId: [gameServerId],
            playerId: [pog.playerId],
            moduleId: [moduleId]
        }
    });

    const currentBalance = variables.data.data.length > 0 ? parseInt(variables.data.data[0].value) : 0;

    if (currentBalance < amount) {
        throw new TakaroUserError(`Insufficient balance. You have ${currentBalance} coins in the bank.`);
    }

    // Give coins FIRST
    await takaro.gameserver.gameServerControllerExecuteCommand(gameServerId, {
        command: `giveplus "${player.name}" casinoCoin ${amount}`
    });

    // THEN deduct balance
    const newBalance = currentBalance - amount;

    await takaro.variable.variableControllerUpdate(variables.data.data[0].id, {
        value: newBalance.toString()
    });

    await takaro.gameserver.gameServerControllerSendMessage(gameServerId, {
        message: `[Bank] Withdrew ${amount} coins. New balance: ${newBalance} coins.`,
        opts: { recipient: { gameId: pog.gameId } }
    });
}

await main();

